/// 清零 BSS 段，确保未初始化的静态变量被正确设置为 0。
pub(crate) unsafe fn clear_bss() {
    unsafe extern "C" {
        fn sbss();
        fn ebss();
    }
    clear_bss_for_loop(sbss as *const () as usize, ebss as *const () as usize);
}

//! # HAL 层
//! HAL（Hardware Abstraction Layer）层定义了与硬件相关的抽象接口，隔离了上层通用逻辑
//! 与具体架构实现之间的依赖关系。
//!
//! HAL 层的接口主要包括与 CPU、内存、分页、异常处理等相关的操作，这些接口由具体架构
